IF OBJECT_ID('Prices', 'U') IS NOT NULL DROP TABLE Prices;
IF OBJECT_ID('Asset', 'U') IS NOT NULL DROP TABLE Asset;
IF OBJECT_ID('Asset_Type', 'U') IS NOT NULL DROP TABLE Asset_Type;
IF OBJECT_ID('Data_Source', 'U') IS NOT NULL DROP TABLE Data_Source;

CREATE TABLE Asset_Type (Asset_Type_ID INT PRIMARY KEY, Type_Name VARCHAR(50));
CREATE TABLE Asset (Asset_ID INT PRIMARY KEY, Ticker_Symbol VARCHAR(20), Asset_Name VARCHAR(100), Asset_Type_ID INT FOREIGN KEY REFERENCES Asset_Type(Asset_Type_ID));
CREATE TABLE Data_Source (Data_Source_ID INT PRIMARY KEY, Source_Name VARCHAR(100), Last_Sync_Time_Stamp DATETIME);
CREATE TABLE Prices (Price_ID INT IDENTITY(1,1) PRIMARY KEY, Asset_ID INT FOREIGN KEY REFERENCES Asset(Asset_ID), Price_Date DATE, Close_Price DECIMAL(18, 2), Volume BIGINT, Data_Source_ID INT FOREIGN KEY REFERENCES Data_Source(Data_Source_ID));


